/**
 * Poisoning test dataset: 50 adversarial + 50 legitimate memories.
 *
 * Each entry has a content string, source domain, expected classification
 * (adversarial or legitimate), and attack category for adversarial entries.
 *
 * The full 450 legit + 50 adversarial set is generated by combining these
 * hand-crafted entries with generated variations in the test runner.
 */

export interface PoisoningEntry {
  content: string;
  sourceSite: string;
  expected: 'adversarial' | 'legitimate';
  category?: string;
}

